example.code:
// WRONG: module-level — shared across all requests
const userLoader = new DataLoader(batchUsers);

export const resolvers = {
  Order: {
    user: (order) => userLoader.load(order.userId), // leaks across users!
  },
};

// CORRECT: per-request context
function createContext(req) {
  return {
    loaders: {
      user: new DataLoader(batchUsers),
      product: new DataLoader(batchProducts),
    },
    userId: req.user?.id,
  };
}

export const resolvers = {
  Order: {
    user: (order, _, ctx) => ctx.loaders.user.load(order.userId),
  },
};

type Query {
  orders(first: Int, after: String, status: OrderStatus): OrderConnection!
}

type OrderConnection {
  edges: [OrderEdge!]!
  pageInfo: PageInfo!
  totalCount: Int!
}

type OrderEdge {
  cursor: String!
  node: Order!
}

type PageInfo {
  hasNextPage: Boolean!
  hasPreviousPage: Boolean!
  startCursor: String
  endCursor: String
}

type Mutation {
  deleteUser(id: ID!): Boolean!  # client cannot update cache
}

type Mutation {
  deleteUser(id: ID!): DeleteUserPayload!
}

type DeleteUserPayload {
  deletedId: ID!
  success: Boolean!
}
